package main

import (
	"crypto/rsa"
	"errors"
	"log"
	"net/http"
	"os"
	"strings"

	// Using actively maintained fork with security fixes
	"github.com/gin-gonic/gin" // v1.9.1 - patched
	"github.com/golang-jwt/jwt/v5" // Maintained fork of jwt-go
)

var publicKey *rsa.PublicKey

func init() {
	// Load RSA public key for JWT verification
	keyData, err := os.ReadFile("/etc/app/jwt-public.pem")
	if err != nil {
		log.Fatalf("Failed to load public key: %v", err)
	}

	publicKey, err = jwt.ParseRSAPublicKeyFromPEM(keyData)
	if err != nil {
		log.Fatalf("Failed to parse public key: %v", err)
	}
}

func main() {
	if os.Getenv("GIN_MODE") == "" {
		gin.SetMode(gin.ReleaseMode)
	}

	router := gin.Default()

	router.GET("/api/data", func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if !strings.HasPrefix(authHeader, "Bearer ") {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "missing token"})
			return
		}

		tokenString := strings.TrimPrefix(authHeader, "Bearer ")

		// SECURE: Explicit algorithm validation prevents confusion attacks
		token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
			// CRITICAL: Validate algorithm is exactly what we expect
			if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
				return nil, errors.New("unexpected signing method")
			}
			return publicKey, nil
		}, jwt.WithValidMethods([]string{"RS256"}))

		if err != nil || !token.Valid {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "invalid token"})
			return
		}

		c.JSON(http.StatusOK, gin.H{"data": "sensitive"})
	})

	router.Run(":8080")
}
