    "github.com/gin-gonic/gin":     ">=1.9.1",
    "github.com/golang-jwt/jwt/v5": ">=5.2.0",
    "golang.org/x/crypto":          ">=0.17.0",
}
```

3. **Runtime integrity verification** - Verify module hashes at startup:
```go
func VerifyRuntimeIntegrity() error {
    buildInfo, ok := debug.ReadBuildInfo()
    if !ok {
        return errors.New("cannot read build info")
    }

    for _, dep := range buildInfo.Deps {
        if dep.Sum == "" {
            return fmt.Errorf("missing checksum for %s", dep.Path)
        }
        // Log for audit trail
        log.Printf("Verified: %s@%s (%s)", dep.Path, dep.Version, dep.Sum[:16])
    }
    return nil
}
