```javascript
// server.js - Secure implementation without vulnerable packages
const express = require('express');
const helmet = require('helmet');
const { URL } = require('url');

const app = express();

// Security headers
app.use(helmet());

// Use built-in argument parsing or validated alternatives
const args = {};
process.argv.slice(2).forEach(arg => {
  const [key, value] = arg.replace(/^--/, '').split('=');
  // Prevent prototype pollution
  if (key && !key.includes('__proto__') && !key.includes('constructor')) {
    args[key] = value || true;
  }
});

// Validate URLs before fetching
const ALLOWED_DOMAINS = ['api.example.com', 'data.example.com'];

app.get('/fetch', async (req, res) => {
  try {
    const url = new URL(req.query.url);

    if (!ALLOWED_DOMAINS.includes(url.hostname)) {
      return res.status(400).json({ error: 'Domain not allowed' });
    }

    if (!['http:', 'https:'].includes(url.protocol)) {
      return res.status(400).json({ error: 'Invalid protocol' });
    }

    // Use native fetch (Node 18+) instead of vulnerable node-fetch
    const response = await fetch(url.toString());
    res.json(await response.json());
  } catch (error) {
    res.status(400).json({ error: 'Invalid URL' });
  }
});

// Never execute user-provided commands
// Remove shell execution endpoint entirely

app.listen(3000);
```

**Key Security Controls**:
- **Exact version pinning**: Using exact versions (e.g., `4.17.21`) instead of ranges prevents unexpected updates
- **Resolutions field**: Forces transitive dependencies to use patched versions
- **npm audit integration**: Automated vulnerability scanning on every install
- **Node.js engine constraint**: Ensures modern Node.js with native secure fetch API
- **Removed vulnerable functionality**: Shell execution removed entirely as defense in depth

