```javascript
// scripts/dependency-scanner.js
const { execSync } = require('child_process');
const https = require('https');
const fs = require('fs');

class DependencySecurityScanner {
  constructor(config) {
    this.config = config;
    this.severityThreshold = {
      critical: 4,
      high: 3,
      moderate: 2,
      low: 1
    };
  }

  async runAudit() {
    const results = {
      timestamp: new Date().toISOString(),
      vulnerabilities: [],
      summary: {},
      actionRequired: false
    };

    try {
      // Run npm audit with JSON output
      const auditOutput = execSync('npm audit --json', {
        encoding: 'utf-8',
        maxBuffer: 10 * 1024 * 1024 // 10MB buffer for large projects
      });

      const audit = JSON.parse(auditOutput);
      results.summary = audit.metadata.vulnerabilities;

      // Process each vulnerability
      for (const [id, vuln] of Object.entries(audit.vulnerabilities || {})) {
        const vulnData = {
          package: vuln.name,
          severity: vuln.severity,
          via: vuln.via,
          range: vuln.range,
          fixAvailable: vuln.fixAvailable,
          cve: this.extractCVE(vuln.via)
        };

        results.vulnerabilities.push(vulnData);

        // Check against severity threshold
        if (this.severityThreshold[vuln.severity] >= 
            this.severityThreshold[this.config.failOnSeverity]) {
          results.actionRequired = true;
        }
      }

    } catch (error) {
      // npm audit exits with code 1 when vulnerabilities found
      if (error.stdout) {
        const audit = JSON.parse(error.stdout);
        results.summary = audit.metadata?.vulnerabilities || {};
        results.actionRequired = true;
      } else {
        throw error;
      }
    }

    return results;
  }

  extractCVE(via) {
    if (Array.isArray(via)) {
      for (const item of via) {
        if (typeof item === 'object' && item.url) {
          const match = item.url.match(/CVE-\d{4}-\d+/);
          if (match) return match[0];
        }
      }
    }
    return null;
  }

  async checkLockfileIntegrity() {
    const lockfilePath = 'package-lock.json';
    const packagePath = 'package.json';

    if (!fs.existsSync(lockfilePath)) {
      return { valid: false, reason: 'No lockfile found' };
    }

    const lockfile = JSON.parse(fs.readFileSync(lockfilePath, 'utf-8'));
    const packageJson = JSON.parse(fs.readFileSync(packagePath, 'utf-8'));

    // Verify lockfile version
    if (lockfile.lockfileVersion < 2) {
      return { 
        valid: false, 
        reason: 'Lockfile version 1 lacks integrity hashes' 
      };
    }

    // Check for integrity hashes
    const packagesWithoutIntegrity = [];
    for (const [name, pkg] of Object.entries(lockfile.packages || {})) {
      if (name && !pkg.integrity && !pkg.link) {
        packagesWithoutIntegrity.push(name);
      }
    }

    if (packagesWithoutIntegrity.length > 0) {
      return {
        valid: false,
        reason: `Missing integrity hashes: ${packagesWithoutIntegrity.slice(0, 5).join(', ')}`
      };
    }

    return { valid: true };
  }

  async scanForMaliciousPackages() {
    const lockfile = JSON.parse(
      fs.readFileSync('package-lock.json', 'utf-8')
    );

    const suspiciousPatterns = [
      /^[a-z]+-[a-z]+-[a-z]+$/,  // Random word combinations
      /^[a-z]{20,}$/,            // Very long single words
      /@[0-9]+\.[0-9]+\.[0-9]+-[a-z]+/, // Unusual prerelease tags
    ];

    const typosquatTargets = [
      { legitimate: 'lodash', typos: ['1odash', 'lodahs', 'lodasH'] },
      { legitimate: 'express', typos: ['expresss', 'expres', 'expr3ss'] },
      { legitimate: 'react', typos: ['raect', 'reacct', 're4ct'] }
    ];

    const warnings = [];

    for (const [name] of Object.entries(lockfile.packages || {})) {
      const pkgName = name.replace('node_modules/', '');

      // Check for typosquatting
      for (const target of typosquatTargets) {
        if (target.typos.includes(pkgName)) {
          warnings.push({
            package: pkgName,
            type: 'typosquatting',
            message: `Possible typosquat of ${target.legitimate}`
          });
        }
      }

      // Check suspicious patterns
      for (const pattern of suspiciousPatterns) {
        if (pattern.test(pkgName) && !this.isKnownLegitimate(pkgName)) {
          warnings.push({
            package: pkgName,
            type: 'suspicious_name',
            message: 'Package name matches suspicious pattern'
          });
        }
      }
    }

    return warnings;
  }

  isKnownLegitimate(name) {
    // Check against known legitimate packages
    const legitimatePackages = new Set([
      'cross-env', 'cross-spawn', 'debug', 'chalk'
    ]);
    return legitimatePackages.has(name);
  }

  async generateSBOM() {
    // Generate Software Bill of Materials
    const sbom = {
      bomFormat: 'CycloneDX',
      specVersion: '1.4',
      version: 1,
      metadata: {
        timestamp: new Date().toISOString(),
        tools: [{ name: 'dependency-scanner', version: '1.0.0' }]
      },
      components: []
    };

    const lockfile = JSON.parse(
      fs.readFileSync('package-lock.json', 'utf-8')
    );

    for (const [name, pkg] of Object.entries(lockfile.packages || {})) {
      if (!name) continue;

      sbom.components.push({
        type: 'library',
        name: name.replace('node_modules/', ''),
        version: pkg.version,
        purl: `pkg:npm/${name.replace('node_modules/', '')}@${pkg.version}`,
        hashes: pkg.integrity ? [
          { alg: 'SHA-512', content: pkg.integrity.replace('sha512-', '') }
        ] : []
      });
    }

    return sbom;
  }

  async alertOnCritical(vulnerabilities) {
    const critical = vulnerabilities.filter(v => v.severity === 'critical');

    if (critical.length === 0) return;

    // Log for monitoring systems (DataDog, Splunk, etc.)
    console.error(JSON.stringify({
      level: 'critical',
      event: 'security.dependency.vulnerability',
      vulnerabilities: critical,
      action_required: true,
      timestamp: new Date().toISOString()
    }));

    // Integrate with alerting (example: PagerDuty)
    if (process.env.PAGERDUTY_KEY) {
      await this.sendPagerDutyAlert(critical);
    }
  }

  async sendPagerDutyAlert(vulnerabilities) {
    const payload = {
      routing_key: process.env.PAGERDUTY_KEY,
      event_action: 'trigger',
      payload: {
        summary: `Critical npm vulnerabilities: ${vulnerabilities.map(v => v.package).join(', ')}`,
        severity: 'critical',
        source: 'dependency-scanner',
        custom_details: { vulnerabilities }
      }
    };
    // Send to PagerDuty Events API
  }
}

// CI/CD Integration
async function main() {
  const scanner = new DependencySecurityScanner({
    failOnSeverity: process.env.SEVERITY_THRESHOLD || 'high'
  });

  console.log('🔍 Starting dependency security scan...\n');

  // Step 1: Lockfile integrity
  const lockfileCheck = await scanner.checkLockfileIntegrity();
  if (!lockfileCheck.valid) {
    console.error(`❌ Lockfile validation failed: ${lockfileCheck.reason}`);
    process.exit(1);
  }
  console.log('✅ Lockfile integrity verified');

  // Step 2: Vulnerability audit
  const auditResults = await scanner.runAudit();
  console.log(`📊 Found: ${JSON.stringify(auditResults.summary)}`);

  // Step 3: Malicious package scan
  const malwareCheck = await scanner.scanForMaliciousPackages();
  if (malwareCheck.length > 0) {
    console.error('⚠️ Suspicious packages detected:', malwareCheck);
  }

  // Step 4: Generate SBOM
  const sbom = await scanner.generateSBOM();
  fs.writeFileSync('sbom.json', JSON.stringify(sbom, null, 2));
  console.log('📋 SBOM generated: sbom.json');

  // Step 5: Alert on critical
  if (auditResults.actionRequired) {
    await scanner.alertOnCritical(auditResults.vulnerabilities);
    console.error('\n❌ Security scan failed - vulnerabilities require attention');
    process.exit(1);
  }

  console.log('\n✅ Security scan passed');
}

main().catch(err => {
  console.error('Scanner error:', err);
  process.exit(1);
});
```

