**2. Runtime Dependency Security Monitoring Service**:

```java
package com.enterprise.security;

import org.springframework.boot.actuate.health.Health;
import org.springframework.boot.actuate.health.HealthIndicator;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Component;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.*;
import java.net.http.*;
import java.time.Duration;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

@Component
public class DependencySecurityMonitor implements HealthIndicator {

    private static final Logger logger = LoggerFactory.getLogger(DependencySecurityMonitor.class);
    private static final String OSV_API = "https://api.osv.dev/v1/query";

    private final HttpClient httpClient;
    private final Map<String, VulnerabilityStatus> vulnerabilityCache;
    private volatile boolean securityCheckPassed = true;
    private volatile int criticalVulnCount = 0;

    public DependencySecurityMonitor() {
        this.httpClient = HttpClient.newBuilder()
            .connectTimeout(Duration.ofSeconds(10))
            .build();
        this.vulnerabilityCache = new ConcurrentHashMap<>();
    }

    @Override
    public Health health() {
        if (!securityCheckPassed) {
            return Health.down()
                .withDetail("reason", "Critical vulnerabilities detected")
                .withDetail("criticalCount", criticalVulnCount)
                .withDetail("action", "Review /actuator/security/vulnerabilities")
                .build();
        }
        return Health.up()
            .withDetail("lastScan", System.currentTimeMillis())
            .withDetail("status", "No critical vulnerabilities")
            .build();
    }

    @Scheduled(cron = "0 0 */4 * * *") // Every 4 hours
    public void scheduledVulnerabilityScan() {
        logger.info("Starting scheduled dependency vulnerability scan");
        try {
            List<DependencyInfo> dependencies = loadDependenciesFromSBOM();
            scanForVulnerabilities(dependencies);
        } catch (Exception e) {
            logger.error("Vulnerability scan failed: {}", e.getMessage(), e);
        }
    }

    private List<DependencyInfo> loadDependenciesFromSBOM() throws IOException {
        // Load from CycloneDX SBOM generated at build time
        List<DependencyInfo> deps = new ArrayList<>();

        try (InputStream is = getClass().getResourceAsStream("/META-INF/sbom/bom.json")) {
            if (is == null) {
                logger.warn("SBOM not found, using classpath scan");
                return scanClasspathDependencies();
            }
            // Parse CycloneDX JSON and extract components
            // Implementation would parse JSON and create DependencyInfo objects
        }
        return deps;
    }

    private List<DependencyInfo> scanClasspathDependencies() {
        List<DependencyInfo> deps = new ArrayList<>();

        // Known critical dependencies to monitor
        Map<String, String> criticalDeps = Map.of(
            "org.apache.logging.log4j:log4j-core", getClassVersion("org.apache.logging.log4j.core.Logger"),
            "com.fasterxml.jackson.core:jackson-databind", getClassVersion("com.fasterxml.jackson.databind.ObjectMapper"),
            "org.yaml:snakeyaml", getClassVersion("org.yaml.snakeyaml.Yaml"),
            "org.springframework:spring-core", getClassVersion("org.springframework.core.SpringVersion")
        );

        criticalDeps.forEach((name, version) -> {
            if (version != null && !version.isEmpty()) {
                String[] parts = name.split(":");
                deps.add(new DependencyInfo(parts[0], parts[1], version));
            }
        });

        return deps;
    }

    private String getClassVersion(String className) {
        try {
            Class<?> clazz = Class.forName(className);
            Package pkg = clazz.getPackage();
            return pkg != null ? pkg.getImplementationVersion() : "unknown";
        } catch (ClassNotFoundException e) {
            return null;
        }
    }

    public void scanForVulnerabilities(List<DependencyInfo> dependencies) {
        int critical = 0;
        int high = 0;

        for (DependencyInfo dep : dependencies) {
            try {
                List<Vulnerability> vulns = queryOSV(dep);

                for (Vulnerability vuln : vulns) {
                    vulnerabilityCache.put(
                        dep.getGroupId() + ":" + dep.getArtifactId(),
                        new VulnerabilityStatus(dep, vuln)
                    );

                    if ("CRITICAL".equals(vuln.severity())) {
                        critical++;
                        logger.error("CRITICAL vulnerability in {}: {} - {}", 
                            dep, vuln.id(), vuln.summary());
                        sendSecurityAlert(dep, vuln);
                    } else if ("HIGH".equals(vuln.severity())) {
                        high++;
                        logger.warn("HIGH severity vulnerability in {}: {}", 
                            dep, vuln.id());
                    }
                }
            } catch (Exception e) {
                logger.error("Failed to scan {}: {}", dep, e.getMessage());
            }
        }

        this.criticalVulnCount = critical;
        this.securityCheckPassed = critical == 0;

        logger.info("Vulnerability scan complete: {} critical, {} high", critical, high);
    }

    private List<Vulnerability> queryOSV(DependencyInfo dep) throws Exception {
        String requestBody = String.format(
            "{\"package\":{\"name\":\"%s:%s\",\"ecosystem\":\"Maven\"},\"version\":\"%s\"}",
            dep.getGroupId(), dep.getArtifactId(), dep.getVersion()
