A comprehensive dependency security strategy requires multiple layers: checksum verification, vulnerability scanning, private module protection, and continuous monitoring. Here's a production-grade approach used by security-conscious organizations.

**PRODUCTION PATTERN**:

```go
package depguard

import (
    "bufio"
    "crypto/sha256"
    "encoding/hex"
    "encoding/json"
    "fmt"
    "io"
    "net/http"
    "os"
    "os/exec"
    "path/filepath"
    "regexp"
    "strings"
    "time"
)

// DependencyGuard provides comprehensive dependency security
type DependencyGuard struct {
    AllowedModules    map[string]bool
    BlockedModules    map[string]string // module -> reason
    PrivatePrefix     string
    VulnDBEndpoint    string
    ChecksumCache     map[string]string
    LastScanTime      time.Time
    MaxDependencyAge  time.Duration
}

// VulnerabilityReport from scanning
type VulnerabilityReport struct {
    Module      string   `json:"module"`
    Version     string   `json:"version"`
    CVEs        []string `json:"cves"`
    Severity    string   `json:"severity"`
    FixVersion  string   `json:"fix_version,omitempty"`
    Description string   `json:"description"`
}

// NewDependencyGuard creates a configured guard
func NewDependencyGuard(privatePrefix string) *DependencyGuard {
    return &DependencyGuard{
        AllowedModules: map[string]bool{
            "golang.org/x/":     true,
            "github.com/sirupsen/logrus": true,
            "github.com/gorilla/mux":     true,
            "github.com/lib/pq":          true,
        },
        BlockedModules: map[string]string{
            "github.com/dgrijalva/jwt-go": "CVE-2020-26160: Use golang-jwt/jwt/v5",
        },
        PrivatePrefix:    privatePrefix,
        VulnDBEndpoint:   "https://vuln.go.dev/",
        ChecksumCache:    make(map[string]string),
        MaxDependencyAge: 180 * 24 * time.Hour, // 6 months
    }
}

// ValidateGoSum verifies go.sum integrity
func (dg *DependencyGuard) ValidateGoSum(goSumPath string) error {
    file, err := os.Open(goSumPath)
    if err != nil {
        return fmt.Errorf("cannot open go.sum: %w", err)
    }
    defer file.Close()

    scanner := bufio.NewScanner(file)
    lineNum := 0

    for scanner.Scan() {
        lineNum++
        line := scanner.Text()
        parts := strings.Fields(line)

        if len(parts) < 3 {
            continue
        }

        module := parts[0]
        version := parts[1]
        checksum := parts[2]

        // Check for blocked modules
        if reason, blocked := dg.BlockedModules[module]; blocked {
            return fmt.Errorf("line %d: blocked module %s: %s", 
                lineNum, module, reason)
        }

        // Validate checksum format (h1:base64hash)
        if !strings.HasPrefix(checksum, "h1:") {
            return fmt.Errorf("line %d: invalid checksum format for %s", 
                lineNum, module)
        }

        // Check for dependency confusion (private module from public source)
        if strings.HasPrefix(module, dg.PrivatePrefix) {
            return fmt.Errorf("line %d: private module %s found in public go.sum", 
                lineNum, module)
        }

        // Verify against allowed list for critical modules
        if !dg.isAllowedModule(module) {
            fmt.Printf("WARNING: Unverified module %s@%s\n", module, version)
        }
    }

    return scanner.Err()
}

func (dg *DependencyGuard) isAllowedModule(module string) bool {
    for prefix := range dg.AllowedModules {
        if strings.HasPrefix(module, prefix) {
            return true
        }
    }
    return false
}

// ScanVulnerabilities uses govulncheck for vulnerability scanning
func (dg *DependencyGuard) ScanVulnerabilities(projectPath string) ([]VulnerabilityReport, error) {
    // Run govulncheck (official Go vulnerability scanner)
    cmd := exec.Command("govulncheck", "-json", "./...")
    cmd.Dir = projectPath

    output, err := cmd.Output()
    if err != nil {
        // govulncheck returns non-zero if vulnerabilities found
        if exitErr, ok := err.(*exec.ExitError); ok {
            output = exitErr.Stderr
        }
    }

    var reports []VulnerabilityReport

    // Parse govulncheck JSON output
    decoder := json.NewDecoder(strings.NewReader(string(output)))
    for decoder.More() {
        var entry map[string]interface{}
        if err := decoder.Decode(&entry); err != nil {
            continue
        }

        if finding, ok := entry["finding"].(map[string]interface{}); ok {
            report := VulnerabilityReport{
                Module:   fmt.Sprintf("%v", finding["module"]),
                Severity: "HIGH",
            }
            if osv, ok := finding["osv"].(string); ok {
                report.CVEs = []string{osv}
            }
            reports = append(reports, report)
        }
    }

    dg.LastScanTime = time.Now()
    return reports, nil
}

// VerifyModuleIntegrity checks module against Go checksum database
func (dg *DependencyGuard) VerifyModuleIntegrity(module, version string) error {
    // Query Go checksum database
    url := fmt.Sprintf("https://sum.golang.org/lookup/%s@%s", 
        module, version)

    client := &http.Client{Timeout: 10 * time.Second}
    resp, err := client.Get(url)
    if err != nil {
        return fmt.Errorf("checksum database unavailable: %w", err)
    }
    defer resp.Body.Close()

    if resp.StatusCode == http.StatusNotFound {
        return fmt.Errorf("module %s@%s not in checksum database", 
            module, version)
    }

    if resp.StatusCode != http.StatusOK {
        return fmt.Errorf("checksum database error: %d", resp.StatusCode)
    }

    body, _ := io.ReadAll(resp.Body)
    lines := strings.Split(string(body), "\n")

    // Cache the verified checksum
    for _, line := range lines {
        if strings.HasPrefix(line, module) {
            parts := strings.Fields(line)
            if len(parts) >= 3 {
                dg.ChecksumCache[module+"@"+version] = parts[2]
            }
        }
    }

    return nil
}

// GenerateSBOM creates Software Bill of Materials
func (dg *DependencyGuard) GenerateSBOM(projectPath string) (string, error) {
    cmd := exec.Command("go", "list", "-m", "-json", "all")
    cmd.Dir = projectPath

    output, err := cmd.Output()
    if err != nil {
        return "", fmt.Errorf("failed to list modules: %w", err)
    }

    type ModuleInfo struct {
        Path    string `json:"Path"`
        Version string `json:"Version"`
        Main    bool   `json:"Main"`
    }

    var sbom struct {
        Generated  time.Time    `json:"generated"`
        Project    string       `json:"project"`
        GoVersion  string       `json:"go_version"`
        Modules    []ModuleInfo `json:"modules"`
    }

    sbom.Generated = time.Now()
    sbom.Project = projectPath

    decoder := json.NewDecoder(strings.NewReader(string(output)))
    for decoder.More() {
        var mod ModuleInfo
        if err := decoder.Decode(&mod); err != nil {
            continue
        }
        if !mod.Main {
            sbom.Modules = append(sbom.Modules, mod)
        }
    }

    result, _ := json.MarshalIndent(sbom, "", "  ")
    return string(result), nil
}
```

