```yaml
# .github/workflows/security-scan.yml
name: Security Scan

on:
  push:
    branches: [main, develop]
  pull_request:
    branches: [main]
  schedule:
    - cron: '0 6 * * *'  # Daily at 6 AM

jobs:
  composer-audit:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4

      - name: Setup PHP
        uses: shivammathur/setup-php@v2
        with:
          php-version: '8.2'
          tools: composer:v2

      - name: Install dependencies
        run: composer install --no-dev --prefer-dist

      - name: Run Composer Audit
        run: |
          composer audit --format=json > audit-results.json
          if jq -e '.advisories | length > 0' audit-results.json; then
            echo "::error::Security vulnerabilities found!"
            cat audit-results.json | jq '.advisories'
            exit 1
          fi

      - name: Check for outdated packages
        run: |
          composer outdated --direct --format=json > outdated.json
          cat outdated.json

      - name: Upload audit results
        uses: actions/upload-artifact@v4
        with:
          name: security-audit
          path: |
            audit-results.json
            outdated.json

  notify-on-vulnerability:
    needs: composer-audit
    if: failure()
    runs-on: ubuntu-latest
    steps:
      - name: Send Slack notification
        uses: slackapi/slack-github-action@v1
        with:
          payload: |
            {
              "text": "🚨 Security vulnerability detected in ${{ github.repository }}"
            }
        env:
          SLACK_WEBHOOK_URL: ${{ secrets.SLACK_SECURITY_WEBHOOK }}
